mapper.select:
select p.id, p.category, p.title, p.content, p.image, p.likes, p.comments, p.date, p.user_id, p.user_name, u.avatar as user_avatar, p.status, p.is_top from post p left join user u on p.user_id = u.id where p.user_id in
#{id}
and p.status = 1 order by p.is_top desc, p.id desc

select p.id, p.category, p.title, p.content, p.image, p.likes, p.comments, p.date, p.user_id, p.user_name, u.avatar as user_avatar, p.status, p.is_top
from post p left join user u on p.user_id = u.id
where p.id = #{id}
